{
  "ruleId": "high-amount-rule",
  "name": "High Amount Rule",
  "description": "Flag transactions with amount > 1000",
  "condition": {
    "type": "GREATER_THAN",
    "field": "amount",
    "value": 1000
  },
  "actions": [{ "type": "FLAG", "severity": "MEDIUM" }],
  "enabled": true
}

{
  "ruleId": "complex-and-rule",
  "name": "Complex AND Rule",
  "description": "High amount AND suspicious currency",
  "condition": {
    "type": "AND",
    "operands": [
      { "type": "GREATER_THAN", "field": "amount", "value": 50000 },
      { "type": "EQUAL", "field": "currency", "value": "USD" }
    ]
  },
  "actions": [{ "type": "FLAG", "severity": "HIGH" }],
  "enabled": true
}

{
  "ruleId": "between-amount-rule",
  "name": "Suspicious Amount Range",
  "description": "Flag amounts between 500K and 1M",
  "condition": {
    "type": "BETWEEN",
    "field": "transferAmount",
    "value": [500000, 1000000]
  },
  "actions": [{ "type": "FLAG", "severity": "MEDIUM" }],
  "enabled": true
}

{
  "ruleId": "merchant-screening-rule",
  "name": "Merchant Screening",
  "description": "Flag merchants containing gambling keyword",
  "condition": {
    "type": "CONTAINS",
    "field": "merchantName",
    "value": "gambling"
  },
  "actions": [{ "type": "FLAG", "severity": "HIGH" }],
  "enabled": true
}

{
  "ruleId": "ip-range-rule",
  "name": "Private IP Check",
  "description": "Flag transactions from private 10.x IPs",
  "condition": {
    "type": "STARTS_WITH",
    "field": "ipAddress",
    "value": "10."
  },
  "actions": [{ "type": "FLAG", "severity": "LOW" }],
  "enabled": true
}

{
  "ruleId": "regex-ip-rule",
  "name": "Regex IP Pattern",
  "description": "Flag IPs matching suspicious pattern",
  "condition": {
    "type": "REGEX",
    "field": "ipAddress",
    "value": "^10\\.0\\..*"
  },
  "actions": [{ "type": "FLAG", "severity": "MEDIUM" }],
  "enabled": true
}

{
  "ruleId": "or-condition-rule",
  "name": "OR Condition Rule",
  "description": "Flag if USD currency OR amount > 500000",
  "condition": {
    "type": "OR",
    "operands": [
      { "type": "EQUAL", "field": "currency", "value": "USD" },
      { "type": "GREATER_THAN", "field": "transferAmount", "value": 500000 }
    ]
  },
  "actions": [{ "type": "FLAG", "severity": "MEDIUM" }],
  "enabled": true
}

{
  "ruleId": "high-amount-rule",
  "name": "Updated High Amount Rule",
  "description": "Updated: Flag transactions with amount > 2000",
  "condition": {
    "type": "GREATER_THAN",
    "field": "amount",
    "value": 2000
  },
  "actions": [{ "type": "FLAG", "severity": "HIGH" }],
  "enabled": true
}
